                  "contents": "{\n  \"label\": \"Tech Stack\",\n  \"description\": \"Technology layers — frontend frameworks, backend runtime, and infrastructure\",\n  \"icon\": \"🔧\",\n  \"color\": \"#9b59b6\",\n  \"renderAs\": \"section\"\n}\n"
